// Parsear webhook de Evolution API
const body = $json.body || $json;
const data = body.data || body;

// Ignorar mensajes propios
if (data.key?.fromMe === true) return [];

// Solo chats privados (no grupos)
const remoteJid = data.key?.remoteJid || '';
if (!remoteJid || remoteJid.endsWith('@g.us') || remoteJid.endsWith('@broadcast')) return [];

const message = data.message || {};
const caption =
  message.imageMessage?.caption ||
  message.extendedTextMessage?.text ||
  message.conversation || '';

const telefono = remoteJid.replace('@s.whatsapp.net', '');
const nombreCliente = data.pushName || null;

// Decodificar código invisible (\u200B=0, \u200C=1, 4 bits por hex char)
function decodeInvisible(text) {
  const zwChars = [...text].filter(c => c === '\u200B' || c === '\u200C');
  if (zwChars.length < 32) return null;
  const bits = zwChars.slice(0, 32).map(c => c === '\u200B' ? '0' : '1').join('');
  let hex = '';
  for (let i = 0; i < 32; i += 4) hex += parseInt(bits.slice(i, i + 4), 2).toString(16);
  return hex;
}

// Caso 1: imagen con código invisible → agregar al carrito
const prendaId = decodeInvisible(caption);
if (prendaId) {
  return [{ json: { tipo: 'carrito_agregar', prendaId, telefono, remoteJid, nombreCliente } }];
}

// Caso 2: texto LISTO → confirmar todas las reservas del carrito
const textoNorm = caption.trim().toUpperCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');
if (textoNorm === 'LISTO') {
  return [{ json: { tipo: 'carrito_confirmar', telefono, remoteJid, nombreCliente } }];
}

// Caso 3: imagen sin código → comprobante de pago
if (message.imageMessage) {
  const mediaUrl = message.imageMessage?.url || null;
  return [{ json: { tipo: 'comprobante', telefono, remoteJid, mediaUrl } }];
}

// Cualquier otro mensaje: ignorar
return [];

const res = $json;
const remoteJid = $('Parsear Mensaje').first().json.remoteJid;

if (!res.ok) {
  return [{ json: { remoteJid, mensaje: 'Esta prenda ya no está disponible. Si crees que es un error, escribinos 😊' } }];
}

const total = res.totalEnCarrito || 1;
const desc = res.desc || 'Prenda';
const yaEstaba = res.yaEstabaEnCarrito;

let mensaje;
if (yaEstaba) {
  mensaje = `Esta prenda ya estaba en tu lista 🛒\n\nTenés ${total} prenda${total > 1 ? 's' : ''} guardada${total > 1 ? 's' : ''}. Mandá más fotos o respondé *LISTO* para reservar todo.`;
} else {
  mensaje = `✅ Guardé *${desc}* en tu lista 🛒\n\nTenés ${total} prenda${total > 1 ? 's' : ''} guardada${total > 1 ? 's' : ''}. Mandá más fotos o respondé *LISTO* para reservar todo.`;
}

return [{ json: { remoteJid, mensaje } }];

const res = $json;
const remoteJid = $('Parsear Mensaje').first().json.remoteJid;

if (!res.reservadas && !res.detalle) {
  return [{ json: { remoteJid, mensaje: 'No tenés prendas guardadas. Reenviá las fotos que te interesan y después respondé *LISTO* 😊' } }];
}

const reservadas = res.reservadas || 0;
const fallidas = res.fallidas || 0;
const detalle = res.detalle || [];

if (reservadas === 0) {
  return [{ json: { remoteJid, mensaje: 'No pudimos reservar ninguna prenda, puede que ya no estén disponibles. Si creés que es un error, escribinos 😊' } }];
}

// Tomar la hora de expiración de la primera reservada (todas tienen la misma)
const horaExp = detalle.find(d => d.ok)?.horaExpiracion || '';

const lista = detalle
  .filter(d => d.ok)
  .map(d => `• ${d.desc}`)
  .join('\n');

let mensaje = `✅ ¡Reservé ${reservadas} prenda${reservadas > 1 ? 's' : ''}!\n\n${lista}\n\nTenés hasta las *${horaExp}* para enviarnos el comprobante de pago. Si no lo mandás a tiempo, las reservas se cancelan automáticamente. 🙌`;

if (fallidas > 0) {
  const listaFallidas = detalle
    .filter(d => !d.ok)
    .map(d => `• ${d.desc}`)
    .join('\n');
  mensaje += `\n\n⚠️ ${fallidas} prenda${fallidas > 1 ? 's' : ''} ya no estaba${fallidas > 1 ? 'n' : ''} disponible${fallidas > 1 ? 's' : ''}:\n${listaFallidas}`;
}

return [{ json: { remoteJid, mensaje } }];
